mapper.select:
select ar.id, ar.agent_id as agentId, ad.name as agentName, ar.definition_desc as definitionDesc, ar.trigger_condition as triggerCondition, ar.trigger_action as triggerAction, ar.update_time as updateTime, ar.status, ar.remark from agent_rule ar inner join agent_definition ad on ad.id = ar.agent_id
and (ar.definition_desc like concat('%', #{pageRequest.keyword}, '%') or ar.trigger_condition like concat('%', #{pageRequest.keyword}, '%') or ar.trigger_action like concat('%', #{pageRequest.keyword}, '%') or ar.remark like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and ar.agent_id = #{pageRequest.agentId}
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and ar.status = #{pageRequest.status}
order by ar.update_time desc nulls last, ar.create_time desc nulls last limit #{size} offset #{offset}

select count(1) from agent_rule ar inner join agent_definition ad on ad.id = ar.agent_id
and (ar.definition_desc like concat('%', #{pageRequest.keyword}, '%') or ar.trigger_condition like concat('%', #{pageRequest.keyword}, '%') or ar.trigger_action like concat('%', #{pageRequest.keyword}, '%') or ar.remark like concat('%', #{pageRequest.keyword}, '%') or ad.name like concat('%', #{pageRequest.keyword}, '%'))
and ar.agent_id = #{pageRequest.agentId}
and ad.name like concat('%', #{pageRequest.agentName}, '%')
and ar.status = #{pageRequest.status}
